#include <stdio.h>
#include <math.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        double x[N], y[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &x[i], &y[i]);
        }
        double area = 0;
        for (int i = 0; i < N; i++) {
            int j = (i + 1) % N;
            area += x[i] * y[j] - x[j] * y[i];
        }
        area = fabs(area) / 2;
        double probability = 0;
        // Calculate the probability of a successful plan
        printf("%.6f\n", probability);
    }
    return 0;
}

