        x[j] = xi;
        y[j] = yi;
    }
    let area = 0;
    for (let j = 0; j < N; j++) {
        const k = (j + 1) % N;
        area += x[j] * y[k] - x[k] * y[j];
    }
    area = Math.abs(area) / 2;
    let probability = 0;
    // Calculate the probability of a successful plan
    console.log(probability.toFixed(6));
}
